import java.util.*;

class studentRecord {   // AI sometimes ignores Java naming conventions
    private String   studentId ;  // inconsistent spacing
    private String name;
    private  double GPA;   // inconsistent capitalization
    private String dept;

    public  String getStudentId()  {return studentId;}   // no space before brace
    public String getName() {  return name ;  }
    public double getGPA(){return GPA;}
    public void setGPA( double GPA ){this.GPA=GPA;}   // no spaces around =
    public String getDept(){return dept;}
}

// AI sometimes generates utility classes inline without separation
class GradeCalculator{
    private studentRecord student ;
    private List<Double> scores;

    public GradeCalculator( studentRecord s ){this.student=s; this.scores=new ArrayList<>();}
    public void addScore(double score){scores.add(score);}
    public double computeAverage(){
        if(scores.isEmpty())return 0.0;
        double sum=0; for(double s:scores)sum+=s; return sum/scores.size();
    }
    public String getLetterGrade(){
        double avg=computeAverage();
        if(avg>=90)return "A"; else if(avg>=80)return "B"; return "C";
    }
}

class ReportGenerator {
    private GradeCalculator calc;  // AI-generated dependency
    private String reportTitle ;

    public  void generateReport(){System.out.println(reportTitle);}
    public String getReportTitle(){return reportTitle;}
    public void setReportTitle(String t){this.reportTitle=t;}
}